-- ============================================================
-- DIAGNÓSTICO: buscar los leads de Fede por teléfono
-- Correr primero el SELECT para ver qué pasa con cada lead.
-- ============================================================

-- PASO 1: Ver cuál es el user_id de Fede
SELECT id, full_name, email, role
FROM public.profiles
WHERE full_name ILIKE '%fede%' OR full_name ILIKE '%federico%' OR email ILIKE '%fede%'
ORDER BY full_name;

-- PASO 2: Buscar los leads por teléfono y ver su estado actual
SELECT
  id,
  first_name,
  last_name,
  phone,
  email,
  current_status,
  is_closed,
  assigned_to_user_id,
  (SELECT full_name FROM public.profiles p WHERE p.id = l.assigned_to_user_id) AS asignado_a,
  batch_id,
  updated_at
FROM public.leads l
WHERE phone IN (
  '50244990907','543855032838','5217752053669','5492616254454','541136552770',
  '51987590992','543764688412','573237335807','5493512478385','5492634367332',
